SELECT ar.approval_id, ar.request_type_code, ar.requester_admin_id, req.name AS requester_name, ar.target_id, ar.status_code, ar.requested_at, ar.completed_at, al.approval_line_id, al.approval_id AS line_approval_id, al.approver_admin_id, apv.name AS approver_name, al.approval_order, al.status_code AS line_status_code, al.comment_text, al.approved_at FROM APPROVAL_REQUESTS ar LEFT JOIN ADMIN_USERS req ON ar.requester_admin_id = req.admin_id LEFT JOIN APPROVAL_LINES al ON ar.approval_id = al.approval_id LEFT JOIN ADMIN_USERS apv ON al.approver_admin_id = apv.admin_id WHERE 1 = 1
AND ar.status_code = #{statusCode}
AND ar.request_type_code = #{requestTypeCode}
ORDER BY ar.requested_at DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(1) FROM APPROVAL_REQUESTS ar
WHERE 1 = 1

  AND ar.status_code       = #{statusCode}


  AND ar.request_type_code = #{requestTypeCode}

